#include <stdio.h>
#define MOD 1000000007
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int upper, d, m, N;
        scanf("%d %d %d %d", &upper, &d, &m, &N);
        int dp[N];
        for (int i = 0; i < N; i++) dp[i] = 0;
        for (int x1 = 0; x1 <= upper; x1++) {
            for (int x2 = 0; x2 <= upper; x2++) {
                for (int x3 = 0; x3 <= upper; x3++) {
                    int sum = (x1 * d + x2 * d + x3 * d) % N;
                    dp[sum] = (dp[sum] + 1) % MOD;
                }
            }
        }
        printf("%d\n", dp[m]);
    }
    return 0;
}

