import java.util.Scanner;
public class Main {
    static final int MOD = 1000000007;
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int upper = sc.nextInt();
            int d = sc.nextInt();
            int m = sc.nextInt();
            int N = sc.nextInt();
            int[] dp = new int[N];
            for (int x1 = 0; x1 <= upper; x1++) {
                for (int x2 = 0; x2 <= upper; x2++) {
                    for (int x3 = 0; x3 <= upper; x3++) {
                        int sum = (x1 * d + x2 * d + x3 * d) % N;
                        dp[sum] = (dp[sum] + 1) % MOD;
                    }
                }
            }
            System.out.println(dp[m]);
        }
    }
}

